private String decodeCopySourceComponent(String value, String copySource) {
    StringBuilder decoded = new StringBuilder(value.length());
    ByteArrayOutputStream bytes = new ByteArrayOutputStream();
    for (int i = 0; i < value.length();) {
        char c = value.charAt(i);
        if (c != '%') {
            decoded.append(c);
            i++;
            continue;
        }

        bytes.reset();
        while (i < value.length() && value.charAt(i) == '%') {
            if (i + 2 >= value.length()) {
                throw new AwsException("InvalidArgument", "Invalid copy source: " + copySource, 400);
            }
            int high = Character.digit(value.charAt(i + 1), 16);
            int low = Character.digit(value.charAt(i + 2), 16);
            if (high < 0 || low < 0) {
                throw new AwsException("InvalidArgument", "Invalid copy source: " + copySource, 400);
            }
            bytes.write((high << 4) + low);
            i += 3;
        }
        decoded.append(new String(bytes.toByteArray(), StandardCharsets.UTF_8));
    }
    return decoded.toString();
}

